function 更新Dialog({ skill, isOpen, onClose, onSuccess }: { 
  skill: SkillDetail | null, isOpen: boolean, onClose: () => void, onSuccess: () => void
}) {
  const [file, setFile] = useState<File | null>(null)
  const [version, set版本号] = useState('')
